// Extract message data from Meta WhatsApp webhook payload
const body = $input.first().json;

// Meta webhook verification (GET requests handled by webhook node)
// For POST: extract message content
let phoneNumber = '';
let messageText = '';
let messageId = '';
let contactName = '';

if (body.entry && body.entry[0] && body.entry[0].changes && body.entry[0].changes[0]) {
  const change = body.entry[0].changes[0];
  if (change.value && change.value.messages && change.value.messages[0]) {
    const msg = change.value.messages[0];
    phoneNumber = msg.from || '';
    messageId = msg.id || '';
    messageText = msg.text?.body || msg.button?.text || msg.interactive?.button_reply?.title || '';

    if (change.value.contacts && change.value.contacts[0]) {
      contactName = change.value.contacts[0].profile?.name || '';
    }
  }
}

// Clean phone number for session ID
const sessionId = phoneNumber.replace(/[^0-9]/g, '');

return {
  json: {
    phoneNumber,
    sessionId,
    messageText,
    messageId,
    contactName,
    timestamp: new Date().toISOString(),
    raw: JSON.stringify(body)
  }
};

// Prepare the AI response and lead data for downstream nodes
const aiResponse = $input.first().json.output || $input.first().json.text || '';
const extractData = $('Extract Message').first().json;

// Simple lead scoring based on conversation content
const responseLower = aiResponse.toLowerCase();
const messageLower = (extractData.messageText || '').toLowerCase();
const combinedText = responseLower + ' ' + messageLower;

let leadScore = 'COLD';
let hasContactInfo = false;
let hasAddress = false;
let hasName = extractData.contactName ? true : false;

// Check for contact information patterns
if (/\b\d{10}\b|\b\d{3}[-\s]\d{3}[-\s]\d{4}\b|\b0\d{2}\s\d{3}\s\d{4}\b/.test(combinedText)) {
  hasContactInfo = true;
}
if (/\bstreet\b|\broad\b|\bavenue\b|\bdrive\b|\bplace\b|\bclose\b|\bblvd\b|\baddress\b/.test(combinedText)) {
  hasAddress = true;
}

// Scoring logic
if (hasContactInfo && hasAddress && /sign\s*up|install|apply|get\s*started|proceed|go\s*ahead|sounds\s*good|interested|let'?s\s*do\s*it/.test(combinedText)) {
  leadScore = 'HOT';
} else if (hasContactInfo || (/price|cost|how\s*much|install|when\s*can|interested|package/.test(combinedText) && hasName)) {
  leadScore = 'WARM';
}

return {
  json: {
    phoneNumber: extractData.phoneNumber,
    sessionId: extractData.sessionId,
    contactName: extractData.contactName,
    incomingMessage: extractData.messageText,
    aiResponse: aiResponse,
    leadScore: leadScore,
    hasContactInfo: hasContactInfo,
    hasAddress: hasAddress,
    timestamp: extractData.timestamp,
    webhookReceived: true
  }
};

